        __m512d br=_mm512_add_pd(x2_re,x5_re), bi=_mm512_add_pd(x2_im,x5_im);
        __m512d er=_mm512_sub_pd(x2_re,x5_re), ei=_mm512_sub_pd(x2_im,x5_im);
        __m512d cr=_mm512_add_pd(x3_re,x4_re), ci=_mm512_add_pd(x3_im,x4_im);
        __m512d fr=_mm512_sub_pd(x3_re,x4_re), fi=_mm512_sub_pd(x3_im,x4_im);

        /* R-term first level (3 independent seeds from x0) */
        __m512d t1r=_mm512_fnmadd_pd(KP900,cr,x0_re), t1i=_mm512_fnmadd_pd(KP900,ci,x0_im);
